import subprocess
import os

def extract_tar(source_file, destination_dir):
    # Validate the source file and destination directory
    if not os.path.exists(source_file) or not os.path.isfile(source_file):
        raise ValueError("Invalid source file")
    if not os.path.exists(destination_dir) or not os.path.isdir(destination_dir):
        raise ValueError("Invalid destination directory")

    # Extract the tar file to the destination directory
    subprocess.run(['tar', '-czf', source_file, destination_dir])